[321] قال ابن جُزي: خَيْرٌ مُسْتَقَرًّا جاء هنا التفضيلُ بيْنَ الجنةِ والنارِ؛ لأنَّ هذا مستقَرٌّ وهذا مستقَرٌّ). ((تفسير ابن جزي)) (2/81). وقال السعدي: (هذا من بابِ استِعمالِ أفعَلِ التفضيلِ فيما ليس في الطَّرَفِ الآخَرِ منه شَيءٌ؛ لأنَّه لا خيرَ في مَقيلِ أهلِ النَّارِ ومُستقَرِّهم، كقَولِه: آَللَّهُ خَيْرٌ أَمَّا يُشْرِكُونَ
[النمل: 59]
). ((تفسير السعدي)) (ص: 581). ويُنظر: ((قواعد التفسير)) للسبت (1/258).

[466] يُنظر: ((تفسير ابن جرير)) (17/446)، ((تفسير القرطبي)) (13/29)، ((تفسير البيضاوي)) (4/123)، ((تفسير ابن كثير)) (6/109)، ((تفسير العليمي)) (5/23)، ((تفسير السعدي)) (ص: 582)، ((تفسير ابن عاشور)) (19/20). ممَّن اختار في الجملةِ أنَّ التَّرتيلَ بمعنى الترسُّلِ، والتَّمكُّثِ شَيئًا بعْدَ شَيءٍ، آياتٍ ثمَّ آياتٍ، على تؤَدَةٍ وتَمهُّلٍ: مقاتلُ بنُ سليمانَ، وابنُ جرير، والزجَّاجُ، والزمخشريُّ، وابن عطية، وابن الجوزي، والرازي، والقرطبي، والبيضاوي، وجلال الدين المحلي، السعدي. يُنظر: ((تفسير مقاتل بن سليمان)) (3/234)، ((تفسير ابن جرير)) (17/446)، ((معاني القرآن وإعرابه)) للزجاج (4/66)، ((تفسير الزمخشري)) (3/278)، ((تفسير ابن عطية)) (4/209)، ((تفسير ابن الجوزي)) (3/320)، ((تفسير الرازي)) (24/457)، ((تفسير القرطبي)) (13/29)، ((تفسير البيضاوي)) (4/123)، ((تفسير الجلالين)) (ص: 474)، ((تفسير السعدي)) (ص: 582). وممَّن قال بنحوِ هذا القولِ مِن السَّلفِ: ابنُ عبَّاسٍ، والنَّخَعيُّ، والحسن، وابن جُرَيج. يُنظر: ((تفسير ابن جرير)) (17/446)، ((تفسير الثعلبي)) (7/132). ومِمَّن اختار أنَّ الترتيلَ بمعنى التَّبيينِ: السمرقنديُّ، وابنُ أبي زمنين. يُنظر: ((تفسير السمرقندي)) (2/537)، ((تفسير ابن أبي زمنين)) (3/259). وممَّن قال بذلك مِن السلفِ: قَتادةُ. يُنظر: ((تفسير ابن كثير)) (6/109). قال العليمي: (وَرَتَّلْنَاهُ تَرْتِيلًا: أنزَلْنا بعضَه في إثرِ بعضٍ، وبيَّنَّاه تبيينًا). ((تفسير العليمي)) (5/23). وقال الثعلبي: (والترتيلُ: التبيينُ في ترسُّلٍ وتثبُّتٍ). ((تفسير الثعلبي)) (7/132). وقال ابن عاشور: (والترتيلُ يوصَفُ به الكلامُ إذا كان حسَنَ التأليفِ، بيِّنَ الدَّلالةِ... والترتيلُ يجوزُ أن يكون حالةً لنزولِ القرآنِ، أي: نزلَّناه مفرَّقًا منسَّقًا في ألفاظِه ومعانيه، غيرَ متراكمٍ، فهو مفرَّقٌ في الزمانِ، فإذا كمل إنزالُ سورةٍ جاءت آياتُها مرتَّبةً متناسِبةً، كأنَّها أُنزلت جُملةً واحدةً، ومفرَّقٌ في التأليفِ بأنه مفصَّلٌ واضحٌ... ويجوزُ أن يرادَ بـ «رتلناه»: أمَرْنا بترتيلِه، أي: بقراءتِه مرَتَّلًا، أي: بتمهُّلٍ بألَّا يُعجِّلَ في قراءتِه؛ بأن تُبيَّنَ جميعُ الحروفِ والحركاتِ بمهلٍ، وهو المذكورُ في سورةِ «المزمل» في قولِه تعالى: وَرَتِّلِ الْقُرْآَنَ تَرْتِيلًا
[المزمل: 4]
). ((تفسير ابن عاشور)) (19/20).

[618] يُنظر: ((تفسير ابن جرير)) (17/459، 460)، ((تفسير القرطبي)) (13/36)، ((تفسير الشوكاني)) (4/90)، ((أضواء البيان)) للشنقيطي (6/59)، ((تفسير ابن عثيمين- سورة الفرقان)) (ص: 180-182). قال القرطبي: (أَمْ تَحْسَبُ أَنَّ أَكْثَرَهُمْ يَسْمَعُونَ سماعَ قَبولٍ، أو يفكِّرون فيما تقولُ فيعقلونه؛ أي: هُم بمنزلةِ مَن لا يعقلُ ولا يسمعُ. وقيل: المعنى: أنَّهم لمَّا لم يَنتفعوا بما يَسمعون فكأنَّهم لم يَسْمعوا). ((تفسير القرطبي)) (13/36). وقال ابن عاشور: (المرادُ مِن نفيِ أنَّ أَكْثَرَهُمْ يَسْمَعُونَ نفيُ أثرِ السماعِ، وهو فَهْمُ الحقِّ؛ لأنَّ ما يُلقيه إليهم الرسولُ صلَّى الله عليه وسلَّم لا يَرتابُ فيه إلَّا مَن هو كالذي لم يسمعْه، وهذا كقولِه تعالى: إِنَّكَ لَا تُسْمِعُ الْمَوْتَى وَلَا تُسْمِعُ الصُّمَّ الدُّعَاءَ إِذَا وَلَّوْا مُدْبِرِينَ
[النمل: 80]
). ((تفسير ابن عاشور)) (19/37).

[1099] يُنظر: ((تفسير ابن جرير)) (17/525)، ((تفسير القرطبي)) (13/80، 81)، ((إغاثة اللهفان من مصايد الشيطان)) لابن القيم (1/241)، ((تفسير ابن كثير)) (6/131)، ((تفسير السعدي)) (ص: 587)، ((تفسير ابن عاشور)) (19/79)، ((أضواء البيان)) للشنقيطي (6/79). قال الرسعني: (مَرُّوا كِرَامًا أي: مرُّوا مرَّ الكرماءِ، مُعرضينَ عنهم، مُكرمينَ أنفسَهم عن التوقُّفِ عليهم، والخوضِ معهم؛ كقوله تعالى: وَإِذَا سَمِعُوا اللَّغْوَ أَعْرَضُوا عَنْهُ
[القصص: 55]
). ((تفسير الرسعني)) (5/358). وقال البقاعي: (مَرُّوا كِرَامًا أي: آمِرينَ بالمعروفِ، ناهينَ عن المنكَرِ -إن تعلَّقَ بهم أمرٌ أو نهيٌ- بإشارةٍ أو عبارةٍ، على حسَبِ ما يَرَونَه نافعًا، أو مُعرِضينَ إن كان لا يصلُحُ شَيءٌ من ذلك؛ لإثارةِ مَفسدةٍ أعظَمَ مِن ذلك أو نحوِه؛ رحمةً لأنفُسِهم وغيرِهم). ((نظم الدرر)) (13/433). ويُنظر: ((تفسير ابن جرير)) (17/525)، ((تفسير ابن عثيمين- سورة الفرقان)) (ص: 316، 317). وقال ابن جرير: (فتأويلُ الكلامِ: وإذا مَرُّوا بالباطِلِ فسَمِعوه أو رَأَوْه، مَرُّوا كِرامًا؛ مُرورُهم كِرامًا في بعضِ ذلك بأنْ لا يَسْمَعوه، وذلك كالغناءِ. وفي بعضِ ذلك بأنْ يُعْرِضوا عنه ويصفحُوا، وذلك إذا أُوذُوا بإسماعِ القبيحِ مِن القولِ. وفي بعضِه بأنْ يَنْهَوْا عن ذلك، وذلك بأنْ يَرَوْا مِن المُنكَرِ ما يُغَيَّرُ بالقولِ فَيُغَيِّرُوه بالقولِ، وفي بعضِه بأنْ يُضارِبوا عليه بالسُّيوفِ، وذلك بأنْ يَرَوْا قومًا يَقْطَعونَ الطَّريقَ على قومٍ، فيَستَصْرِخُهم المُرادُ ذلك منهم، فيُصْرِخونَهم، وكلُّ ذلك مُرورُهم كِرامًا). ((تفسير ابن جرير)) (17/525).

[1107] قيل: الغرفةُ: المنزلةُ الرَّفيعةُ، والدرجةُ العاليةُ في الجنَّةِ. وممَّن قال بذلك: ابنُ جرير، والثعلبيُّ، والبغويُّ، والخازنُ، وجلال الدين المحليُّ، والشوكانيُّ، والقاسميُّ. يُنظر: ((تفسير ابن جرير)) (17/534)، ((تفسير الثعلبي)) (7/153)، ((تفسير البغوي)) (3/460)، ((تفسير الخازن)) (3/320)، ((تفسير الجلالين)) (ص: 479)، ((تفسير الشوكاني)) (4/105)، ((تفسير القاسمي)) (7/446). وقال الزمخشري: (المرادُ: يُجْزَونَ الغُرُفاتِ، وهي العَلاليُّ في الجنَّةِ، فوَحَّدَ اقتِصارًا على الواحدِ الدالِّ على الجنسِ، والدَّليلُ على ذلك قولُه: وَهُمْ فِي الْغُرُفَاتِ آَمِنُونَ
[سبأ: 37]
). ((تفسير الزمخشري)) (3/296). ويُنظر: ((تفسير البيضاوي)) (4/132)، ((تفسير النسفي)) (2/552). وقال الشنقيطي: (الظاهرُ أنَّ المرادَ بالغُرفةِ في هذه الآية الكريمةِ جِنسُها الصادِقُ بغُرَفٍ كثيرةٍ). ((أضواء البيان)) (6/81). وقيل: هي الجنَّةُ. وممَّن قال بذلك: ابنُ كثيرٍ، وقال: (قال أبو جَعفرٍ الباقِرُ، وسعيدُ بنُ جُبَيْرٍ، والضَّحَّاكُ، والسُّدِّيُّ: سُمِّيَتْ بذلك؛ لارتِفاعِها). ((تفسير ابن كثير)) (6/133). قال الماوَرْديُّ: (قولُه تعالى: أُولَئِكَ يُجْزَوْنَ الْغُرْفَةَ فيها وجهانِ؛ أحدُهما: أنَّ الغُرفةَ الجنَّةُ، قاله الضحَّاكُ. الثَّاني: أنَّها أعلى مَنازِلِ الجنَّةِ وأفضَلُها، كما أنَّ الغُرفةَ أعلى مَنازلِ الدُّنيا). ((تفسير الماوردي)) (4/161).
